class Base {
public:
 virtual void show() {
 cout << "Base show()" << endl;
 }
 virtual ~Base() { } // Virtual destructor
};

class Derived : public Base {
public:
 void show() override { // override specifier
 cout << "Derived show()" << endl;
 }
};

int main() {
 Base* ptr = new Derived();
 ptr->show(); // Calls Derived::show() at runtime
 delete ptr; // Proper cleanup with virtual destructor
 return 0;
}

class Shape {
public:
 virtual double area() = 0; // Pure virtual
 virtual void display() = 0; // Pure virtual
 virtual ~Shape() { }
};

class Circle : public Shape {
 double radius;
public:
 Circle(double r) : radius(r) { }
 double area() override {
 return 3.14159 * radius * radius;
 }
 void display() override {
 cout << "Circle with radius " << radius << endl;
 }
};

int main() {
 // Shape s; // Error: cannot instantiate abstract class
 Shape* ptr = new Circle(5.0);
 cout << "Area: " << ptr->area() << endl;
 delete ptr;
 return 0;
}

class Base {
public:
 // Non-virtual destructor - PROBLEM!
 ~Base() {
 cout << "Base destructor" << endl;
 }
};

class Derived : public Base {
 int* data;
public:
 Derived() { data = new int[100]; }
 ~Derived() {
 delete[] data;
 cout << "Derived destructor" << endl;
 }
};

int main() {
 Base* ptr = new Derived();
 delete ptr; // Only Base destructor called - MEMORY LEAK!
 return 0;
}

class Base {
public:
 virtual ~Base() {
 cout << "Base virtual destructor" << endl;
 }
};

class Derived : public Base {
 int* data;
public:
 Derived() { data = new int[100]; }
 ~Derived() override {
 delete[] data;
 cout << "Derived destructor" << endl;
 }
};

int main() {
 Base* ptr = new Derived();
 delete ptr;
 // Output: Derived destructor, Base virtual destructor
 return 0;
}

