class Base {
public:
 int x;
 virtual void show() { cout << "Base: " << x << endl; }
};

class Derived : public Base {
public:
 int y;
 void show() override { cout << "Derived: " << x << ", " << y << endl; }
};

int main() {
 Derived d;
 d.x = 10; d.y = 20;

 // Slicing - derived part lost!
 Base b = d; 
 b.show(); // Calls Base::show()

 // Solution: Use pointer or reference
 Base* ptr = &d; // No slicing
 ptr->show(); // Calls Derived::show()

 Base& ref = d; // No slicing
 ref.show(); // Calls Derived::show()

 return 0;
}
